ValidationRule.errorConditionFormula:
(
ISBLANK(BillingStreet) || ISBLANK(BillingCity) || ISBLANK(BillingState) || ISBLANK(BillingPostalCode) || ISBLANK(BillingCountry)
) ||
(
!From_Lead_Convert__c && !Shipping_Same_as_Billing_Address__c  && (ISBLANK(ShippingStreet) || ISBLANK(ShippingCity) || ISBLANK(ShippingState) || ISBLANK(ShippingPostalCode) || ISBLANK(ShippingCountry))
)
